import React, { useState, useEffect } from 'react';
import JSZip from 'jszip';
import './App.css';

const logoImg = require('./WhatsApp Image 2026-07-20 at 9.49.24 PM.jpeg');

const IMAGES = {
  curtainHero: 'https://images.unsplash.com/photo-1513694203232-719a280e022f?auto=format&fit=crop&w=1600&q=80',
  curtainDrapes: 'https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?auto=format&fit=crop&w=800&q=80',
  mosquitoNet: 'https://images.unsplash.com/photo-1628177142898-93e36e4e3a50?auto=format&fit=crop&w=800&q=80',
  sheerCurtains: 'https://images.unsplash.com/photo-1540518614846-7eded433c457?auto=format&fit=crop&w=800&q=80',
  windowFitting: 'https://images.unsplash.com/photo-1615873968403-89e068629265?auto=format&fit=crop&w=800&q=80',
};

function App() {
  const [openingComplete, setOpeningComplete] = useState(false);
  const [activeTab, setActiveTab] = useState('home');
  const [zipImages, setZipImages] = useState([]);
  const [isLoadingZip, setIsLoadingZip] = useState(true);

  // 1. Opening Spotlight Reveal Animation Timer
  useEffect(() => {
    const timer = setTimeout(() => setOpeningComplete(true), 2500);
    return () => clearTimeout(timer);
  }, []);

  // 2. Load catalog.zip for ZIP-enabled pages
  useEffect(() => {
    async function loadCatalogZip() {
      try {
        const response = await fetch('/catalog.zip');
        if (!response.ok) throw new Error('ZIP file not found in public/');
        
        const blob = await response.blob();
        const zip = new JSZip();
        const zipContent = await zip.loadAsync(blob);
        const imagePromises = [];

        zipContent.forEach((relativePath, zipEntry) => {
          if (!zipEntry.dir && /\.(png|jpe?g|svg|webp|gif)$/i.test(zipEntry.name)) {
            const promise = zipEntry.async('blob').then((imgBlob) => ({
              name: zipEntry.name,
              url: URL.createObjectURL(imgBlob),
            }));
            imagePromises.push(promise);
          }
        });

        const extractedImages = await Promise.all(imagePromises);
        setZipImages(extractedImages);
      } catch (err) {
        console.log('Place catalog.zip in client/public/ to auto-load ZIP portfolio.', err);
      } finally {
        setIsLoadingZip(false);
      }
    }

    loadCatalogZip();
  }, []);

  return (
    <div className="app-container" style={{ minHeight: '100vh', background: '#0a0a0a', color: '#fff' }}>
      
      {/* CSS STYLES & ANIMATIONS */}
      <style>{`
        /* Golden Spotlight Aperture Opening Animation */
        .intro-overlay {
          position: fixed;
          top: 0;
          left: 0;
          width: 100vw;
          height: 100vh;
          background: #000;
          z-index: 9999;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          transition: transform 1.2s cubic-bezier(0.77, 0, 0.175, 1), opacity 1s ease;
        }
        .intro-overlay.reveal {
          transform: scale(1.1);
          opacity: 0;
          pointer-events: none;
        }
        .spotlight-ring {
          width: 180px;
          height: 180px;
          border-radius: 50%;
          border: 2px solid #d4af37;
          box-shadow: 0 0 35px rgba(212, 175, 55, 0.8);
          display: flex;
          align-items: center;
          justify-content: center;
          animation: pulseRing 1.8s infinite ease-in-out;
        }
        @keyframes pulseRing {
          0% { transform: scale(0.95); box-shadow: 0 0 20px rgba(212, 175, 55, 0.4); }
          50% { transform: scale(1.05); box-shadow: 0 0 50px rgba(212, 175, 55, 0.9); }
          100% { transform: scale(0.95); box-shadow: 0 0 20px rgba(212, 175, 55, 0.4); }
        }

        /* Font Animations */
        @keyframes fadeInText {
          0% { opacity: 0; transform: translateY(20px); }
          100% { opacity: 1; transform: translateY(0); }
        }
        @keyframes goldShimmer {
          0% { text-shadow: 0 0 4px rgba(212, 175, 55, 0.2); }
          50% { text-shadow: 0 0 16px rgba(212, 175, 55, 0.8); }
          100% { text-shadow: 0 0 4px rgba(212, 175, 55, 0.2); }
        }

        .animated-heading {
          animation: fadeInText 1.2s ease-out forwards, goldShimmer 3s infinite ease-in-out;
        }
        .animated-card {
          transition: transform 0.4s ease, box-shadow 0.4s ease, border-color 0.4s ease;
        }
        .animated-card:hover {
          transform: translateY(-8px);
          border-color: #d4af37 !important;
          box-shadow: 0 10px 25px rgba(212, 175, 55, 0.25);
        }
        .social-icon {
          width: 40px;
          height: 40px;
          border-radius: 50%;
          border: 1px solid #d4af37;
          display: inline-flex;
          align-items: center;
          justify-content: center;
          color: #d4af37;
          text-decoration: none;
          font-weight: bold;
          transition: all 0.3s ease;
        }
        .social-icon:hover {
          background: #d4af37;
          color: #000;
          box-shadow: 0 0 12px rgba(212, 175, 55, 0.8);
          transform: scale(1.1);
        }
      `}</style>

      {/* NEW SPOTLIGHT INTRO ANIMATION */}
      <div className={`intro-overlay ${openingComplete ? 'reveal' : ''}`}>
        <div className="spotlight-ring">
          <img src={logoImg} alt="Jillu Curtains" style={{ width: '120px', borderRadius: '50%' }} />
        </div>
        <h2 className="gold-text animated-heading" style={{ marginTop: '25px', letterSpacing: '3px' }}>JILLU CURTAINS</h2>
        <p style={{ color: '#aaa', fontSize: '0.9rem', letterSpacing: '1px', marginTop: '5px' }}>BESPOKE CURTAINS & MOSQUITO NETS</p>
      </div>

      {/* HEADER NAVBAR */}
      <header className="navbar">
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img src={logoImg} alt="Logo" style={{ height: '45px' }} />
          <span className="gold-text animated-heading" style={{ fontSize: '1.3rem', fontWeight: 'bold' }}>JILLU CURTAINS</span>
        </div>
        <ul className="nav-links">
          {['home', 'about', 'services', 'gallery', 'contact'].map((tab) => (
